//帮别人调
#include<bits/stdc++.h>
using namespace std;
const int N=314;
int n,m,k,s,t,a[N],sum[N],f[N][N];
int main(){
    cin>>n;
    memset(f,127,sizeof(f));
    for(int i=1;i<=n;++i){
        cin>>a[i];
        sum[i]=sum[i-1]+a[i];
        f[i][i]=0;
    }
    for(int len=2;len<=n;++len){//len<=n
        for(int l=1;l+len-1<=n;++l){//要减1
            int r=l+len-1;
            for(int k=l;k<r;++k){
                f[l][r]=min(f[l][r],f[l][k]+f[k+1][r]+sum[r]-sum[l-1]);
                //是min,不是max
                //状态转移方程错了
            }
        }
    }
    cout<<f[1][n];
}
